const NP_STYLES = {
  'Hoboken Homeless Home': { bg: 'linear-gradient(135deg,#C62828,#E53935)', catColor: '#C62828', catBg: '#FFEBEE' },
  'Windham Mountain Conservatory': { bg: 'linear-gradient(135deg,#0D4A8A,#1A6EB5)', catColor: '#1A6EB5', catBg: '#E3F0FB' },
  'Center For Sight Restoration': { bg: 'linear-gradient(135deg,#14507F,#2E86C1)', catColor: '#1A6EB5', catBg: '#E3F0FB' },
  'Bergen County Rescue Shelter': { bg: 'linear-gradient(135deg,#6A1B9A,#AB47BC)', catColor: '#6A1B9A', catBg: '#F3E5F5' },
  'Hudson Valley Trail Society': { bg: 'linear-gradient(135deg,#2E7D32,#66BB6A)', catColor: '#2E7D32', catBg: '#E8F5E9' },
};

function resolvePhotoMeta(entry) {
  return EVENT_PHOTO_MANIFEST[entry.assetKey] || { photoCount: 1, photoExt: { 1: 'jpg' } };
}

function buildPhotos(entry) {
  const { photoCount, photoExt = {} } = resolvePhotoMeta(entry);
  return Array.from({ length: photoCount }, (_, i) => {
    const n = i + 1;
    const ext = photoExt[n] || photoExt[String(n)] || 'jpg';
    return photoPath(entry.assetKey, n, ext);
  });
}

export function buildEvents(seOrganizer) {
  return EVENT_CATALOG.map((entry) => {
    const photos = buildPhotos(entry);
    const style = NP_STYLES[entry.nonprofit] || { bg: 'linear-gradient(135deg,#0A2E52,#1A6EB5)', catColor: '#1A6EB5', catBg: '#E3F0FB' };
    const npInit = npInitials(entry.nonprofit);

    return {
      id: entry.id,
      key: entry.key,
      title: entry.title,
      subtitle: entry.mission,
      mission: entry.mission,
      story: entry.mission,
      organizer: seOrganizer.name,
      initials: seOrganizer.initials,
      nonprofit: entry.nonprofit,
      npInitials: npInit,
      npBg: style.bg,
      category: entry.category,
      catColor: style.catColor,
      catBg: style.catBg,
      date: 'TBA',
      startTime: 'TBA',
      endTime: 'TBA',
      location: 'TBA',
      backed: 0,
      joined: 0,
      updates: photos.length,
      chatCount: 0,
      raised: 0,
      isLive: true,
      cover: photos[0],
      photos,
      tags: [entry.category],
    };
  });
}

export function buildNonprofits(eventList) {
  const seen = new Set();
  return eventList
    .filter((ev) => {
      if (seen.has(ev.nonprofit)) return false;
      seen.add(ev.nonprofit);
      return true;
    })
    .map((ev, idx) => ({
      id: idx + 1,
      name: ev.nonprofit,
      category: ev.category,
      verified: true,
      color: ev.catColor,
      initials: ev.npInitials,
      bg: ev.npBg,
      mission: ev.mission,
    }));
}

/** Display hashtag — title is already stored with # prefix from source data. */
export function eventDisplayTitle(title) {
  return title.startsWith('#') ? title : `#${title.replace(/[\s,'']+/g, '')}`;
}

/** Banner / story / feed card image — always the main cover. */
export function getEventBanner(event) {
  return event?.cover || event?.photos?.[0] || null;
}

/**
 * Vertical focal point for the wide desktop hero banner, per event.
 * The hero is a short 4:1 strip, so a plain centre crop lands on the wrong
 * band for some photos (scenic selfies keep faces low, portraits keep them
 * high). These per-cover values keep each event's subject in view.
 */
const BANNER_FOCUS = {
  'neon-night': 'center 42%',
  'golf-outing': 'center 50%',
  'dog-dad': 'center 30%',
  'give-now': 'center 60%',
  'breakneck-ridge-run': 'center 68%',
};

export function getEventBannerFocus(event) {
  return BANNER_FOCUS[event?.key] || 'center 45%';
}

/** Unique community / gallery photos — all event images except the cover. */
export function getCommunityPhotos(event) {
  if (!event?.photos?.length) return [];
  const cover = getEventBanner(event);
  const seen = new Set();
  return event.photos.filter((src) => {
    if (!src || src === cover || seen.has(src)) return false;
    seen.add(src);
    return true;
  });
}
